package com.google.gson.extras.examples.rawcollections;

import static org.mockito.Mockito.mockStatic;
import static org.mockito.Mockito.when;

import java.io.ByteArrayOutputStream;
import java.io.PrintStream;

import com.google.gson.Gson;
import com.google.gson.JsonArray;
import com.google.gson.JsonParser;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class RawCollectionsExampleTest {

  private final PrintStream originalOut = System.out;
  private ByteArrayOutputStream outContent;

  @BeforeEach
  void setUp() {
    outContent = new ByteArrayOutputStream();
    System.setOut(new PrintStream(outContent));
  }

  @AfterEach
  void tearDown() {
    System.setOut(originalOut);
  }

  @Test
  void testMain_printsExpectedOutput() throws Exception {
    RawCollectionsExample.main(new String[0]);

    String output = outContent.toString().replaceAll("\\r\\n", "\n");

    // Check first line contains the JSON string of the raw collection
    org.junit.jupiter.api.Assertions.assertTrue(
        output.contains("Using Gson.toJson() on a raw collection: [\"hello\",5,{\"type\":\"GREETINGS\",\"source\":\"guest\"}]"),
        "Output did not contain expected JSON serialization line");

    // Check second line contains the formatted output with message, number and event
    org.junit.jupiter.api.Assertions.assertTrue(
        output.contains("Using Gson.fromJson() to get: hello, 5, Event[type=GREETINGS, source=guest]"),
        "Output did not contain expected deserialization line");
  }
}
